# @cctt_verify {"v":2,"sym":"sympy.geometry.tests.test_line.feq","kind":"function","src_hash":"7e5f2619e6f320ce","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"feq(a, )","rhs":"test if two floating point values are 'equal'","over":{"base":"Any"},"name":"feq_correct"},"guarantee":"test if two floating point values are 'equal'","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.geometry.tests.test_line.feq_correct","statement":"Path(feq(x), test if two floating point values are 'equal')"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"9f26203589660d7f"}
def feq(a, b):
    """Test if two floating point values are 'equal'."""
    t_float = Float("1.0E-10")
    return -t_float < a - b < t_float


