# @cctt_verify {"v":2,"sym":"sympy.geometry.tests.test_line.test_angle_between","kind":"function","src_hash":"de576f9bf390bd02","in":{"base":"Any"},"out":{"base":"Any","pred":"Line(a, o).angle_between(Line(b, o)) == pi / 2"},"spec":{"lhs":"test_angle_between()","rhs":"test_angle_between produces the expected output","over":{"base":"Any"},"name":"test_angle_between_correct"},"guarantee":"test_angle_between produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.geometry.tests.test_line.test_angle_between_correct","statement":"Path(test_angle_between(x), test_angle_between produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c47bcc6180d10342"}
def test_angle_between():
    a = Point(1, 2, 3, 4)
    b = a.orthogonal_direction
    o = a.origin
    assert feq(Line.angle_between(Line(Point(0, 0), Point(1, 1)),
                                  Line(Point(0, 0), Point(5, 0))).evalf(), pi.evalf() / 4)
    assert Line(a, o).angle_between(Line(b, o)) == pi / 2
    z = Point3D(0, 0, 0)
    assert Line3D.angle_between(Line3D(z, Point3D(1, 1, 1)),
                                Line3D(z, Point3D(5, 0, 0))) == acos(sqrt(3) / 3)
    # direction of points is used to determine angle
    assert Line3D.angle_between(Line3D(z, Point3D(1, 1, 1)),
                                Line3D(Point3D(5, 0, 0), z)) == acos(-sqrt(3) / 3)


