# @cctt_verify {"v":2,"sym":"sympy.geometry.tests.test_line.test_arguments","kind":"function","src_hash":"efbd789c54970031","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"test_arguments()","rhs":"functions accepting `point` objects in `geometry` should also accept tuples, lists, and generators and automatically convert them to points","over":{"base":"Any"},"name":"test_arguments_correct"},"guarantee":"functions accepting `point` objects in `geometry` should also accept tuples, lists, and generators and automatically convert them to points","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.geometry.tests.test_line.test_arguments_correct","statement":"Path(test_arguments(x), functions accepting `point` objects in `geometry` should also accept tuples, lists, and generators and automatically convert them to points)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"e33262df964c8f82"}
def test_arguments():
    """Functions accepting `Point` objects in `geometry`
    should also accept tuples, lists, and generators and
    automatically convert them to points."""
    from sympy.utilities.iterables import subsets

    singles2d = ((1, 2), [1, 3], Point(1, 5))
    doubles2d = subsets(singles2d, 2)
    l2d = Line(Point2D(1, 2), Point2D(2, 3))
    singles3d = ((1, 2, 3), [1, 2, 4], Point(1, 2, 6))
    doubles3d = subsets(singles3d, 2)
    l3d = Line(Point3D(1, 2, 3), Point3D(1, 1, 2))
    singles4d = ((1, 2, 3, 4), [1, 2, 3, 5], Point(1, 2, 3, 7))
    doubles4d = subsets(singles4d, 2)
    l4d = Line(Point(1, 2, 3, 4), Point(2, 2, 2, 2))
    # test 2D
    test_single = ['contains', 'distance', 'equals', 'parallel_line', 'perpendicular_line', 'perpendicular_segment',
                   'projection', 'intersection']
    for p in doubles2d:
        Line2D(*p)
    for func in test_single:
        for p in singles2d:
            getattr(l2d, func)(p)
    # test 3D
    for p in doubles3d:
        Line3D(*p)
    for func in test_single:
        for p in singles3d:
            getattr(l3d, func)(p)
    # test 4D
    for p in doubles4d:
        Line(*p)
    for func in test_single:
        for p in singles4d:
            getattr(l4d, func)(p)


