# @cctt_verify {"v":2,"sym":"sympy.geometry.tests.test_line.test_perpendicular_line","kind":"function","src_hash":"0a0485b6220cdaa3","in":{"base":"Any"},"out":{"base":"Any","pred":"p.p1 == p3 and p.p2 in l and p.p1 == p3 and p.direction.unit == (p3 - l.projection(p3)).unit"},"spec":{"lhs":"test_perpendicular_line()","rhs":"test_perpendicular_line produces the expected output","over":{"base":"Any"},"name":"test_perpendicular_line_correct"},"guarantee":"test_perpendicular_line produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.geometry.tests.test_line.test_perpendicular_line_correct","statement":"Path(test_perpendicular_line(x), test_perpendicular_line produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"81c5eab3c67ab487"}
def test_perpendicular_line():
    # 3d - requires a particular orthogonal to be selected
    p1, p2, p3 = Point(0, 0, 0), Point(2, 3, 4), Point(-2, 2, 0)
    l = Line(p1, p2)
    p = l.perpendicular_line(p3)
    assert p.p1 == p3
    assert p.p2 in l
    # 2d - does not require special selection
    p1, p2, p3 = Point(0, 0), Point(2, 3), Point(-2, 2)
    l = Line(p1, p2)
    p = l.perpendicular_line(p3)
    assert p.p1 == p3
    # p is directed from l to p3
    assert p.direction.unit == (p3 - l.projection(p3)).unit


