# @cctt_verify {"v":2,"sym":"sympy.geometry.tests.test_line.test_bisectors","kind":"function","src_hash":"ebfade198424904e","in":{"base":"Any"},"out":{"base":"Any","pred":"a(*l1).bisectors(b(*l2)) == ans"},"spec":{"lhs":"test_bisectors()","rhs":"test_bisectors produces the expected output","over":{"base":"Any"},"name":"test_bisectors_correct"},"guarantee":"test_bisectors produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.geometry.tests.test_line.test_bisectors_correct","statement":"Path(test_bisectors(x), test_bisectors produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"6b91b050b674b1ac"}
def test_bisectors():
    r1 = Line3D(Point3D(0, 0, 0), Point3D(1, 0, 0))
    r2 = Line3D(Point3D(0, 0, 0), Point3D(0, 1, 0))
    bisections = r1.bisectors(r2)
    assert bisections == [Line3D(Point3D(0, 0, 0), Point3D(1, 1, 0)),
        Line3D(Point3D(0, 0, 0), Point3D(1, -1, 0))]
    ans = [Line3D(Point3D(0, 0, 0), Point3D(1, 0, 1)),
        Line3D(Point3D(0, 0, 0), Point3D(-1, 0, 1))]
    l1 = (0, 0, 0), (0, 0, 1)
    l2 = (0, 0), (1, 0)
    for a, b in cartes((Line, Segment, Ray), repeat=2):
        assert a(*l1).bisectors(b(*l2)) == ans


